import { Foo } from './foo';

interface User {
    id: number;
    name: string;
    email?: string;
}

type Maybe<T> = T | null;

export function lookup(users: User[], id: number): Maybe<User> {
    for (const user of users) {
        if (user.id === id) {
            return user;
        }
    }
    return null;
}

class Repository<T> {
    private items: T[] = [];

    add(item: T): void {
        this.items.push(item);
        if (this.items.length > 1000) {
            this.items.shift();
        }
    }
}
